const { PrismaClient } = require('@prisma/client');
const { Pool } = require('pg');
const { PrismaPg } = require('@prisma/adapter-pg');

const pool = new Pool({ connectionString: process.env.DATABASE_URL });
const adapter = new PrismaPg(pool);
const prisma = new PrismaClient({ adapter });

async function main() {
  const users = await prisma.user.findMany({
    select: { id: true, email: true, role: true }
  });
  console.log(JSON.stringify(users, null, 2));
}

main().finally(() => {
    prisma.$disconnect();
    pool.end();
});

const fs = require('fs');

try {
  const data = fs.readFileSync('lint-results.json', 'utf8');
  const jsonStart = data.indexOf('[');
  if (jsonStart === -1) {
    console.log("No JSON found");
    process.exit(1);
  }
  const json = JSON.parse(data.substring(jsonStart));
  const summary = json.filter(f => f.errorCount > 0 || f.warningCount > 0).map(f => {
    return {
      file: f.filePath.split('fixtrack\\\\')[1] || f.filePath,
      errors: f.errorCount,
      warnings: f.warningCount,
      messages: Array.from(new Set(f.messages.map(m => m.ruleId + ": " + m.message)))
    };
  });
  console.log(JSON.stringify(summary, null, 2));
} catch (e) {
  console.error("Error reading or parsing", e);
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { createClient } from '@/lib/supabase/client';

export default function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  
  const router = useRouter();
  const supabase = createClient();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setErrorMessage('');

    try {
      const { data, error } = await supabase.auth.signInWithPassword({
        email,
        password,
      });

      if (error) {
        setErrorMessage(error.message);
        return;
      }

      if (data.user) {
        const response = await fetch('/api/auth/login', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ userId: data.user.id }),
        });

        const result = await response.json();

        if (!response.ok) {
          setErrorMessage(result.message || 'An error occurred during login validation.');
          // Sign out the user if verification fails
          await supabase.auth.signOut();
          return;
        }

        const role = result.role;

        if (role === 'ADMIN') {
          router.push('/admin/dashboard');
        } else if (role === 'TECHNICIAN') {
          router.push('/technician/dashboard');
        } else {
          router.push('/dashboard');
        }
      }
    } catch (err: any) {
      setErrorMessage(err.message || 'An unexpected error occurred');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <main className="flex min-h-screen w-full flex-col lg:flex-row overflow-hidden bg-surface-container-lowest">
      {/* Left Panel: Brand & Context (60%) */}
      <div className="hidden lg:flex lg:w-[60%] bg-primary-container relative flex-col justify-between p-12 overflow-hidden">
        <div 
          className="absolute inset-0 z-0 opacity-20 mix-blend-overlay pointer-events-none" 
          style={{ backgroundImage: "url('https://lh3.googleusercontent.com/aida-public/AB6AXuC_89p-O4X-7UzRnI6BKqLCV5owJqCB7eaSY6mcgpTpvKks89Ky5guf1XtWkh3Ka5zWM6GIIHywk31xISzVYEECa8_YRzWpjMpq5LctUZwp7_GQmBfwV8nnUPNplANioUj29LrqxtzjHmBfoK6DtJKgGaGIHFHmsN-5aJs_U4Ka-e0ErxkTjswGTYML3wnQhlT2Q7Yt-WyUyPMDhBl1fJM5Isu43YP3zF4kxrrslUNC-y5EIKsIeD4CO3VQ5lcHmznQYCzE69z2Y_c')", backgroundSize: 'cover', backgroundPosition: 'center' }}
        >
        </div>
        <div className="absolute inset-0 z-10 bg-gradient-to-b from-primary-container/40 to-primary-container/90 pointer-events-none"></div>
        <div className="relative z-20 flex flex-col items-center justify-center flex-grow text-center">
          <div className="flex items-center justify-center w-20 h-20 bg-surface-container-lowest rounded-xl shadow-2xl mb-8">
            <span className="material-symbols-outlined text-primary-container" style={{ fontSize: '48px', fontVariationSettings: "'FILL' 1" }}>domain</span>
          </div>
          <h1 className="font-h1 text-h1 text-on-primary mb-4 tracking-tighter" style={{ fontSize: '4rem' }}>FixTrack</h1>
          <p className="font-h2 text-h2 text-primary-fixed-dim font-light">Smart Maintenance. Zero Delays.</p>
        </div>
        <div className="relative z-20 mt-auto">
          <p className="font-sidebar-label text-sidebar-label text-on-primary-container mb-6 text-center uppercase tracking-widest opacity-80">Integrated Portal Access</p>
          <div className="grid grid-cols-3 gap-6">
            <div className="bg-surface-container-lowest/10 backdrop-blur-md border border-surface-container-lowest/20 rounded-xl p-6 flex flex-col items-center text-center transition-transform hover:-translate-y-1 duration-300">
              <div className="w-12 h-12 rounded-full bg-surface-container-lowest/20 flex items-center justify-center mb-4 text-on-primary">
                <span className="material-symbols-outlined" style={{ fontVariationSettings: "'FILL' 1" }}>person</span>
              </div>
              <h3 className="font-label-md text-label-md text-on-primary mb-2">User</h3>
              <p className="font-body-sm text-body-sm text-primary-fixed-dim opacity-80">Submit & track requests</p>
            </div>
            <div className="bg-surface-container-lowest/10 backdrop-blur-md border border-surface-container-lowest/20 rounded-xl p-6 flex flex-col items-center text-center transition-transform hover:-translate-y-1 duration-300">
              <div className="w-12 h-12 rounded-full bg-surface-container-lowest/20 flex items-center justify-center mb-4 text-on-primary">
                <span className="material-symbols-outlined" style={{ fontVariationSettings: "'FILL' 1" }}>admin_panel_settings</span>
              </div>
              <h3 className="font-label-md text-label-md text-on-primary mb-2">Admin</h3>
              <p className="font-body-sm text-body-sm text-primary-fixed-dim opacity-80">Manage assets & teams</p>
            </div>
            <div className="bg-surface-container-lowest/10 backdrop-blur-md border border-surface-container-lowest/20 rounded-xl p-6 flex flex-col items-center text-center transition-transform hover:-translate-y-1 duration-300">
              <div className="w-12 h-12 rounded-full bg-surface-container-lowest/20 flex items-center justify-center mb-4 text-on-primary">
                <span className="material-symbols-outlined" style={{ fontVariationSettings: "'FILL' 1" }}>build</span>
              </div>
              <h3 className="font-label-md text-label-md text-on-primary mb-2">Technician</h3>
              <p className="font-body-sm text-body-sm text-primary-fixed-dim opacity-80">Execute work orders</p>
            </div>
          </div>
        </div>
      </div>
      
      {/* Right Panel: Login Form (40%) */}
      <div className="flex-1 lg:w-[40%] bg-surface-container-lowest flex flex-col justify-center px-8 sm:px-16 lg:px-24 py-12 relative z-10 shadow-[-20px_0_40px_-15px_rgba(0,0,0,0.1)]">
        <div className="w-full max-w-md mx-auto">
          <div className="flex lg:hidden items-center justify-center mb-10 gap-3">
            <div className="flex items-center justify-center w-10 h-10 bg-primary-container rounded-lg shadow-md">
              <span className="material-symbols-outlined text-on-primary text-xl" style={{ fontVariationSettings: "'FILL' 1" }}>domain</span>
            </div>
            <span className="font-h2 text-h2 text-primary-container tracking-tighter">FixTrack</span>
          </div>
          
          <div className="mb-10 text-center lg:text-left">
            <h2 className="font-h1 text-h1 text-on-surface mb-2">Welcome Back</h2>
            <p className="font-body text-body text-on-surface-variant">Sign in to your FixTrack account</p>
          </div>
          
          <form className="space-y-6" onSubmit={handleSubmit}>
            <div className="space-y-2">
              <label className="font-label-md text-label-md text-on-surface block" htmlFor="email">Email Address</label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                  <span className="material-symbols-outlined text-outline-variant">mail</span>
                </div>
                <input 
                  className="w-full bg-surface font-body text-body text-on-surface border border-outline-variant rounded-lg pl-12 pr-4 py-3 focus:outline-none focus:ring-2 focus:ring-secondary focus:border-transparent transition-shadow placeholder:text-outline-variant/60" 
                  id="email" 
                  name="email" 
                  placeholder="name@institution.edu" 
                  required 
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  disabled={isLoading}
                />
              </div>
            </div>
            
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <label className="font-label-md text-label-md text-on-surface block" htmlFor="password">Password</label>
                <Link className="font-body-sm text-body-sm text-secondary hover:text-secondary-container transition-colors" href="#">Forgot password?</Link>
              </div>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                  <span className="material-symbols-outlined text-outline-variant">lock</span>
                </div>
                <input 
                  className="w-full bg-surface font-body text-body text-on-surface border border-outline-variant rounded-lg pl-12 pr-12 py-3 focus:outline-none focus:ring-2 focus:ring-secondary focus:border-transparent transition-shadow placeholder:text-outline-variant/60" 
                  id="password" 
                  name="password" 
                  placeholder="••••••••" 
                  required 
                  type={showPassword ? "text" : "password"}
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  disabled={isLoading}
                />
                <button 
                  className="absolute inset-y-0 right-0 pr-4 flex items-center text-outline-variant hover:text-on-surface transition-colors" 
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  disabled={isLoading}
                >
                  <span className="material-symbols-outlined">
                    {showPassword ? "visibility" : "visibility_off"}
                  </span>
                </button>
              </div>
            </div>
            
            <button 
              className="w-full bg-secondary hover:bg-secondary-container text-on-primary font-label-md text-label-md py-4 rounded-lg shadow-[0_4px_12px_rgba(37,99,235,0.2)] transition-all hover:shadow-[0_6px_16px_rgba(37,99,235,0.3)] active:scale-[0.98] flex items-center justify-center gap-2 mt-8 disabled:opacity-70 disabled:cursor-not-allowed" 
              type="submit"
              disabled={isLoading}
            >
              {isLoading ? (
                <>
                  <svg className="animate-spin -ml-1 mr-2 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Signing in...
                </>
              ) : (
                <>
                  Login
                  <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>arrow_forward</span>
                </>
              )}
            </button>
            
            {errorMessage && (
              <div className="mt-4 p-4 bg-error-container text-on-error-container rounded-lg text-sm flex items-start gap-3">
                <span className="material-symbols-outlined">error</span>
                <p>{errorMessage}</p>
              </div>
            )}
          </form>
          
          <div className="mt-8 text-center">
            <p className="font-body text-body text-on-surface-variant">
              Don't have an account?{' '}
              <Link className="text-secondary font-medium hover:underline underline-offset-4 transition-all" href="/register">Register here</Link>
            </p>
          </div>
          
          <div className="mt-16 pt-8 border-t border-surface-variant text-center">
            <div className="inline-flex items-center justify-center gap-2 bg-surface-container-low px-4 py-2 rounded-full border border-surface-variant">
              <span className="material-symbols-outlined text-outline text-sm" style={{ fontSize: '16px' }}>info</span>
              <p className="font-body-sm text-body-sm text-outline">
                You will be automatically redirected to your assigned portal based on your role.
              </p>
            </div>
          </div>
        </div>
      </div>
    </main>
  );
}

'use client';

import { useState } from 'react';
import Link from 'next/link';

export default function RegisterPage() {
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [idNumber, setIdNumber] = useState('');
  const [department, setDepartment] = useState('');
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  
  const [isLoading, setIsLoading] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMessage(null);
    setSuccessMessage(null);

    // Basic required field validation
    if (!firstName || !lastName || !email || !idNumber || !department || !password || !confirmPassword) {
      setErrorMessage('All fields are required.');
      return;
    }

    if (password.length < 8) {
      setErrorMessage('Password must be at least 8 characters.');
      return;
    }

    if (password !== confirmPassword) {
      setErrorMessage('Passwords do not match.');
      return;
    }

    setIsLoading(true);

    try {
      const response = await fetch('/api/auth/register', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          firstName,
          lastName,
          email,
          idNumber,
          department,
          password,
        }),
      });

      const data = await response.json();

      if (!response.ok) {
        setErrorMessage(data.message || 'An error occurred during registration.');
        return;
      }

      setSuccessMessage('Registration successful! Your account is now active. You can log in immediately.');
      
      // Clear form
      setFirstName('');
      setLastName('');
      setEmail('');
      setIdNumber('');
      setDepartment('');
      setPassword('');
      setConfirmPassword('');
    } catch (err: any) {
      setErrorMessage(err.message || 'An unexpected error occurred. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen w-full bg-surface-container-lowest overflow-hidden">
      {/* Left Panel (Brand / Image) */}
      <div className="hidden lg:flex w-[45%] bg-primary-container relative flex-col justify-between p-12 overflow-hidden">
        <div className="absolute inset-0 w-full h-full opacity-40 mix-blend-overlay">
          {/* eslint-disable-next-line @next/next/no-img-element */}
          <img 
            alt="Corporate modern aesthetic" 
            className="w-full h-full object-cover grayscale brightness-75" 
            src="https://lh3.googleusercontent.com/aida-public/AB6AXuDqwK9SGAj-2N7cZTRGjWucfLLzY7q7bMUQ6P-splLp1nwc8B8J_1rT9yP-Bm51YJO2BjbJW7REg99KjgrrjX80YF-nBTwVlZsa63Bffqx07hA7vESeZccWghrV85BqJLl5nLlPz350jsD5te0BAXfG3jZdCYtT7fGU_xke9ec_MsER7pTDeKR3Qd8E-fTMAB8yb4f9oOLRpW9kkkH62Suxowdf2e4SZ-4VNIVK7bCkpWoZ9I_EEmUdjS14aCokkUYI2c-CzVgX-S4"
          />
        </div>
        <div className="absolute inset-0 bg-gradient-to-br from-primary-container/90 to-primary/95"></div>
        <div className="relative z-10">
          <div className="flex items-center gap-2 mb-8 text-on-primary">
            <span className="material-symbols-outlined text-h1 font-h1" style={{ fontVariationSettings: "'FILL' 1" }}>dashboard</span>
            <span className="font-h2 text-h2 uppercase tracking-tighter">FIXTRACK</span>
          </div>
        </div>
        <div className="relative z-10 max-w-md">
          <h2 className="font-h1 text-h1 text-on-primary mb-6">Systematic Order & High-Velocity Efficiency.</h2>
          <p className="font-body text-body text-primary-fixed-dim">
            Join the administrative platform built to handle complex facility operations with absolute precision and clarity.
          </p>
        </div>
      </div>
      
      {/* Right Panel (Registration Form) */}
      <div className="w-full lg:w-[55%] min-h-screen flex flex-col justify-center p-12 overflow-y-auto">
        <div className="w-full max-w-[512px] mx-auto pb-12 pt-8">
          <div className="mb-8">
            <h1 className="font-sans text-h1 text-on-surface mb-2">Create Your Account</h1>
            <p className="font-sans text-body text-on-surface-variant">Fill in your details to request system access</p>
          </div>
          
          {/* Info Box */}
          <div className="mb-8 bg-tertiary-fixed/30 border border-tertiary-fixed rounded-lg p-4 flex items-start gap-4">
            <span className="material-symbols-outlined text-tertiary-container mt-1">info</span>
            <p className="font-body-sm text-body-sm text-on-tertiary-fixed-variant leading-snug">
              Registration is open to Students, Faculty, and Staff of the Polytechnic College of La Union. Your account will be activated immediately upon registration.
            </p>
          </div>
          
          {/* Form */}
          <form className="space-y-6" onSubmit={handleSubmit}>
            {/* First & Last Name */}
            <div className="flex flex-col sm:flex-row gap-6">
              <div className="flex-1 flex flex-col gap-2">
                <label className="font-label-md text-label-md text-on-surface-variant" htmlFor="firstName">First Name</label>
                <input 
                  className="w-full bg-surface-container-lowest border border-outline-variant rounded-DEFAULT px-4 py-3 font-body-sm text-body-sm text-on-surface placeholder:text-outline focus:outline-none focus:border-secondary focus:ring-1 focus:ring-secondary transition-colors" 
                  id="firstName" 
                  name="firstName" 
                  placeholder="Enter first name" 
                  required 
                  type="text"
                  value={firstName}
                  onChange={(e) => setFirstName(e.target.value)}
                  disabled={isLoading || successMessage !== null}
                />
              </div>
              <div className="flex-1 flex flex-col gap-2">
                <label className="font-label-md text-label-md text-on-surface-variant" htmlFor="lastName">Last Name</label>
                <input 
                  className="w-full bg-surface-container-lowest border border-outline-variant rounded-DEFAULT px-4 py-3 font-body-sm text-body-sm text-on-surface placeholder:text-outline focus:outline-none focus:border-secondary focus:ring-1 focus:ring-secondary transition-colors" 
                  id="lastName" 
                  name="lastName" 
                  placeholder="Enter last name" 
                  required 
                  type="text"
                  value={lastName}
                  onChange={(e) => setLastName(e.target.value)}
                  disabled={isLoading || successMessage !== null}
                />
              </div>
            </div>
            
            {/* Email */}
            <div className="flex flex-col gap-2">
              <label className="font-label-md text-label-md text-on-surface-variant" htmlFor="email">Email</label>
              <input 
                className="w-full bg-surface-container-lowest border border-outline-variant rounded-DEFAULT px-4 py-3 font-body-sm text-body-sm text-on-surface placeholder:text-outline focus:outline-none focus:border-secondary focus:ring-1 focus:ring-secondary transition-colors" 
                id="email" 
                name="email" 
                placeholder="name@institution.edu" 
                required 
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                disabled={isLoading || successMessage !== null}
              />
            </div>
            
            {/* ID Number */}
            <div className="flex flex-col gap-2">
              <label className="font-label-md text-label-md text-on-surface-variant" htmlFor="idNumber">ID Number</label>
              <input 
                className="w-full bg-surface-container-lowest border border-outline-variant rounded-DEFAULT px-4 py-3 font-body-sm text-body-sm text-on-surface placeholder:text-outline focus:outline-none focus:border-secondary focus:ring-1 focus:ring-secondary transition-colors" 
                id="idNumber" 
                name="idNumber" 
                placeholder="Enter institutional ID" 
                required 
                type="text"
                value={idNumber}
                onChange={(e) => setIdNumber(e.target.value)}
                disabled={isLoading || successMessage !== null}
              />
            </div>
            
            {/* Department */}
            <div className="flex flex-col gap-2">
              <label className="font-label-md text-label-md text-on-surface-variant" htmlFor="department">Department</label>
              <div className="relative">
                <select 
                  className="w-full appearance-none bg-surface-container-lowest border border-outline-variant rounded-DEFAULT px-4 py-3 pr-8 font-body-sm text-body-sm text-on-surface focus:outline-none focus:border-secondary focus:ring-1 focus:ring-secondary transition-colors" 
                  id="department" 
                  name="department" 
                  required
                  value={department}
                  onChange={(e) => setDepartment(e.target.value)}
                  disabled={isLoading || successMessage !== null}
                >
                  <option disabled value="">Select department</option>
                  <option value="CIT">CIT</option>
                  <option value="Engineering">Engineering</option>
                  <option value="Sciences">Sciences</option>
                  <option value="Administration">Administration</option>
                  <option value="Maintenance">Maintenance</option>
                </select>
                <span className="material-symbols-outlined absolute right-4 top-1/2 -translate-y-1/2 text-outline pointer-events-none">expand_more</span>
              </div>
            </div>
            
            {/* Password */}
            <div className="flex flex-col gap-2">
              <label className="font-label-md text-label-md text-on-surface-variant" htmlFor="password">Password</label>
              <input 
                className="w-full bg-surface-container-lowest border border-outline-variant rounded-DEFAULT px-4 py-3 font-body-sm text-body-sm text-on-surface placeholder:text-outline focus:outline-none focus:border-secondary focus:ring-1 focus:ring-secondary transition-colors" 
                id="password" 
                name="password" 
                placeholder="Create a strong password" 
                required 
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                disabled={isLoading || successMessage !== null}
              />
            </div>
            
            {/* Confirm Password */}
            <div className="flex flex-col gap-2">
              <label className="font-label-md text-label-md text-on-surface-variant" htmlFor="confirmPassword">Confirm Password</label>
              <input 
                className="w-full bg-surface-container-lowest border border-outline-variant rounded-DEFAULT px-4 py-3 font-body-sm text-body-sm text-on-surface placeholder:text-outline focus:outline-none focus:border-secondary focus:ring-1 focus:ring-secondary transition-colors" 
                id="confirmPassword" 
                name="confirmPassword" 
                placeholder="Repeat password" 
                required 
                type="password"
                value={confirmPassword}
                onChange={(e) => setConfirmPassword(e.target.value)}
                disabled={isLoading || successMessage !== null}
              />
            </div>
            
            {/* Submit Button */}
            <div className="pt-2">
              <button 
                className="w-full flex justify-center items-center py-4 px-8 bg-secondary hover:bg-secondary/90 text-on-secondary font-label-md text-label-md rounded-lg shadow-sm transition-all active:scale-[0.98] disabled:opacity-70 disabled:cursor-not-allowed" 
                type="submit"
                disabled={isLoading || successMessage !== null}
              >
                {isLoading ? (
                  <>
                    <svg className="animate-spin -ml-1 mr-2 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
