'use client';

import { use, useEffect, useState, useCallback } from 'react';
import Link from 'next/link';
import RequestInfoCard from '@/components/admin/RequestInfoCard';
import RequestStatusStepper from '@/components/admin/RequestStatusStepper';
import AdminActionCard from '@/components/admin/AdminActionCard';
import ActivityLog from '@/components/admin/ActivityLog';

export default function AdminRequestDetailPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);
  const [request, setRequest] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  const fetchRequest = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch(`/api/admin/requests/${id}`);
      if (res.ok) {
        const data = await res.json();
        setRequest(data);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  }, [id]);

  useEffect(() => {
    fetchRequest();
  }, [fetchRequest]);

  if (loading) {
    return <div className="p-8 text-center text-slate-500 font-medium">Loading request details...</div>;
  }

  if (!request) {
    return <div className="p-8 text-center text-error font-medium">Request not found.</div>;
  }

  return (
    <div className="w-full">
      {/* ── Page Header ── */}
      <div className="mb-6">
        <Link 
          href="/admin/requests"
          className="inline-flex items-center gap-1 text-sm font-medium text-slate-500 hover:text-[#2563EB] transition-colors"
        >
          <span className="material-symbols-outlined text-[18px]">arrow_back</span>
          Back to All Requests
        </Link>
      </div>

      <div className="mb-8">
        <h1 className="font-h1 text-h1 text-slate-900 leading-tight">
          Triage Request: REQ-{request.requestCode}
        </h1>
        <p className="text-sm text-slate-500 mt-1">
          Review details, update priority, and assign to a technician.
        </p>
      </div>

      {/* ── Main Layout ── */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
        {/* Left Column (Details & Log) */}
        <div className="lg:col-span-2 flex flex-col gap-6">
          <RequestStatusStepper 
            status={request.status} 
            hasRepairNote={!!request.repairNote} 
          />
          <RequestInfoCard request={request} />
          <ActivityLog statusHistory={request.statusHistory || []} />
        </div>

        {/* Right Column (Actions) */}
        <div className="lg:col-span-1">
          <AdminActionCard request={request} onRefresh={fetchRequest} />
        </div>
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import RequestsFilterBar from '@/components/admin/RequestsFilterBar';
import AllRequestsTable, { type RequestRow } from '@/components/admin/AllRequestsTable';
import Pagination from '@/components/admin/Pagination';

// ── Page Component ────────────────────────────────────────────────────────────

export default function AdminRequestsPage() {
  const router = useRouter();

  // ── Data state ──────────────────────────────────────────────────────────────
  const [requests, setRequests] = useState<RequestRow[]>([]);
  const [total, setTotal] = useState(0);
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [isLoading, setIsLoading] = useState(true);

  // ── Selection state ─────────────────────────────────────────────────────────
  const [selectedIds, setSelectedIds] = useState<string[]>([]);

  // ── Filter state ─────────────────────────────────────────────────────────────
  const [search, setSearch] = useState('');
  const [statusFilter, setStatusFilter] = useState('');
  const [urgencyFilter, setUrgencyFilter] = useState('');
  const [buildingFilter, setBuildingFilter] = useState('');
  const [assignedToFilter, setAssignedToFilter] = useState('');
  const [issueTypeFilter, setIssueTypeFilter] = useState('');
  const [dateFrom, setDateFrom] = useState('');
  const [dateTo, setDateTo] = useState('');

  // ── Technicians list for More Filters ───────────────────────────────────────
  const [technicians, setTechnicians] = useState<
    { id: string; firstName: string; lastName: string }[]
  >([]);

  // ── Fetch technicians on mount ───────────────────────────────────────────────
  useEffect(() => {
    async function loadTechnicians() {
      try {
        const res = await fetch('/api/users?role=TECHNICIAN&limit=100');
        if (res.ok) {
          const data = await res.json();
          setTechnicians(data.users ?? []);
        }
      } catch {
        // Silently fail — technician filter will just be empty
      }
    }
    loadTechnicians();
  }, []);

  // ── Core fetch function ──────────────────────────────────────────────────────
  const fetchRequests = useCallback(
    async (overridePage?: number) => {
      setIsLoading(true);
      try {
        const params = new URLSearchParams();
        params.set('page', String(overridePage ?? page));
        params.set('limit', '10');
        if (search) params.set('search', search);
        if (statusFilter) params.set('status', statusFilter);
        if (urgencyFilter) params.set('urgency', urgencyFilter);
        if (buildingFilter) params.set('building', buildingFilter);
        if (assignedToFilter) params.set('assignedTo', assignedToFilter);
        if (issueTypeFilter) params.set('issueType', issueTypeFilter);
        if (dateFrom) params.set('dateFrom', dateFrom);
        if (dateTo) params.set('dateTo', dateTo);

        const res = await fetch(`/api/admin/requests?${params.toString()}`);
        if (!res.ok) throw new Error('Failed to fetch');
        const data = await res.json();
        setRequests(data.requests ?? []);
        setTotal(data.total ?? 0);
        setTotalPages(data.totalPages ?? 1);
        setPage(data.page ?? 1);
      } catch (err) {
        console.error('Failed to fetch requests:', err);
      } finally {
        setIsLoading(false);
      }
    },
    // eslint-disable-next-line react-hooks/exhaustive-deps
    [page, search, statusFilter, urgencyFilter, buildingFilter, assignedToFilter, issueTypeFilter, dateFrom, dateTo]
  );

  // ── On mount + page change ───────────────────────────────────────────────────
  useEffect(() => {
    fetchRequests();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [page]);

  // ── Filter handlers ──────────────────────────────────────────────────────────
  const handleApply = () => {
    setSelectedIds([]);
    fetchRequests(1);
    setPage(1);
  };

  const handleReset = () => {
    setSearch('');
    setStatusFilter('');
    setUrgencyFilter('');
    setBuildingFilter('');
    setAssignedToFilter('');
    setIssueTypeFilter('');
    setDateFrom('');
    setDateTo('');
    setSelectedIds([]);
    setPage(1);
    // Re-fetch with no filters
    setTimeout(() => fetchRequests(1), 0);
  };

  const handlePageChange = (newPage: number) => {
    setPage(newPage);
    setSelectedIds([]);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // ── Selection handlers ───────────────────────────────────────────────────────
  const handleSelectAll = (checked: boolean) => {
    setSelectedIds(checked ? requests.map((r) => r.id) : []);
  };

  const handleSelectOne = (id: string, checked: boolean) => {
    setSelectedIds((prev) =>
      checked ? [...prev, id] : prev.filter((sid) => sid !== id)
    );
  };

  // ── Row action handlers ──────────────────────────────────────────────────────
  const handleView = (id: string) => {
    router.push(`/admin/requests/${id}`);
  };

  const handleAssign = (id: string) => {
    router.push(`/admin/assignments?requestId=${id}`);
  };

  const handleReject = (id: string) => {
    // Screen 23 (Reject/Cancel Modal) — placeholder until that screen is built
    console.log('[Reject] Request ID:', id);
    alert(`Reject Modal — Screen 23 not yet built. Request ID: ${id}`);
  };

  // ── Bulk export (placeholder) ────────────────────────────────────────────────
  const handleExport = () => {
    console.log('[Export] All requests');
  };

  const handleExportSelected = () => {
    console.log('[Export Selected]', selectedIds);
  };

  const handleBulkAssign = () => {
    console.log('[Bulk Assign]', selectedIds);
    alert(`Bulk Assign — ${selectedIds.length} request(s) selected. Assign UI coming in Screen 12.`);
  };

  // ── Render ────────────────────────────────────────────────────────────────────
  return (
    <div className="w-full">
      {/* ── Page Header ── */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6">
        <div>
          <h1 className="font-h1 text-h1 text-slate-900 leading-tight">
            All Maintenance Requests
          </h1>
          <p className="text-sm text-slate-500 mt-1">
            Manage and track all facility maintenance tickets.
          </p>
        </div>
        <div className="flex items-center gap-3 flex-shrink-0">
          {/* Export */}
          <button
            onClick={handleExport}
            className="flex items-center gap-2 px-4 py-2.5 bg-white border border-[#2563EB] text-[#2563EB] rounded-lg text-sm font-medium hover:bg-blue-50 transition-colors shadow-sm"
            id="btn-export-all"
          >
            <span className="material-symbols-outlined text-[18px]">export_notes</span>
            Export
          </button>
          {/* Bulk Assign */}
          <button
            onClick={handleBulkAssign}
            className="flex items-center gap-2 px-4 py-2.5 bg-[#2563EB] text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors shadow-sm"
            id="btn-bulk-assign"
          >
            <span className="material-symbols-outlined text-[18px]">group_add</span>
            Bulk Assign
          </button>
        </div>
      </div>

      {/* ── Filter Bar ── */}
      <RequestsFilterBar
        search={search}
        statusFilter={statusFilter}
        urgencyFilter={urgencyFilter}
        buildingFilter={buildingFilter}
        assignedToFilter={assignedToFilter}
        issueTypeFilter={issueTypeFilter}
        dateFrom={dateFrom}
        dateTo={dateTo}
        technicians={technicians}
        onSearchChange={setSearch}
        onStatusChange={setStatusFilter}
        onUrgencyChange={setUrgencyFilter}
        onBuildingChange={setBuildingFilter}
        onAssignedToChange={setAssignedToFilter}
        onIssueTypeChange={setIssueTypeFilter}
        onDateFromChange={setDateFrom}
        onDateToChange={setDateTo}
        onApply={handleApply}
        onReset={handleReset}
      />

      {/* ── Bulk Action Bar — appears when checkboxes are selected ── */}
      {selectedIds.length > 0 && (
        <div className="mb-4 px-5 py-3 bg-[#DBEAFE] border border-[#93c5fd] rounded-xl flex flex-col sm:flex-row sm:items-center justify-between gap-3 shadow-sm">
          <p className="text-sm font-semibold text-[#1E3A8A]">
            <span className="material-symbols-outlined text-[16px] mr-1 align-middle">check_circle</span>
            {selectedIds.length} {selectedIds.length === 1 ? 'request' : 'requests'} selected
          </p>
          <div className="flex items-center gap-3">
            <button
              onClick={handleBulkAssign}
              className="flex items-center gap-1.5 px-4 py-2 bg-[#2563EB] text-white rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors"
              id="btn-bulk-assign-selection"
            >
              <span className="material-symbols-outlined text-[16px]">group_add</span>
              Bulk Assign
            </button>
            <button
              onClick={handleExportSelected}
              className="flex items-center gap-1.5 px-4 py-2 bg-white border border-[#2563EB] text-[#2563EB] rounded-lg text-sm font-medium hover:bg-blue-50 transition-colors"
              id="btn-export-selected"
            >
              <span className="material-symbols-outlined text-[16px]">export_notes</span>
              Export Selected
            </button>
            <button
              onClick={() => setSelectedIds([])}
              className="text-sm text-slate-500 hover:text-slate-700 font-medium underline underline-offset-2 transition-colors"
              id="btn-clear-selection"
            >
              Clear Selection
            </button>
          </div>
        </div>
      )}

      {/* ── Table ── */}
      <AllRequestsTable
        requests={requests}
        selectedIds={selectedIds}
        isLoading={isLoading}
        onSelectAll={handleSelectAll}
        onSelectOne={handleSelectOne}
        onView={handleView}
        onAssign={handleAssign}
        onReject={handleReject}
      />

      {/* ── Pagination ── */}
      {!isLoading && total > 0 && (
        <Pagination
          page={page}
          totalPages={totalPages}
          total={total}
          limit={10}
          onPageChange={handlePageChange}
        />
      )}
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import { useRouter, useParams } from 'next/navigation';
import UserForm, { UserFormData } from '@/components/admin/UserForm';
import Toast from '@/components/shared/Toast';

export default function EditUserPage() {
  const router = useRouter();
  const params = useParams<{ id: string }>();
  const userId = params?.id ?? '';

  const [initialData, setInitialData] = useState<Partial<UserFormData> | null>(null);
  const [fullName, setFullName] = useState('');
  const [isLoadingUser, setIsLoadingUser] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [toast, setToast] = useState<{ show: boolean; message: string; type: 'success' | 'error' }>({
    show: false,
    message: '',
    type: 'success',
  });

  const showToast = (message: string, type: 'success' | 'error') => {
    setToast({ show: true, message, type });
  };

  // Fetch user on mount
  useEffect(() => {
    if (!userId) return;

    const fetchUser = async () => {
      setIsLoadingUser(true);
      try {
        const res = await fetch(`/api/admin/users/${userId}`);
        if (res.status === 404) {
          showToast('User not found.', 'error');
          setTimeout(() => router.push('/admin/users'), 1500);
          return;
        }
        if (!res.ok) throw new Error('Failed to fetch user');

        const user = await res.json();
        setFullName(`${user.firstName} ${user.lastName}`);
        setInitialData({
          firstName: user.firstName ?? '',
          lastName: user.lastName ?? '',
          email: user.email ?? '',
          idNumber: user.idNumber ?? '',
          department: user.department ?? '',
          contactNumber: user.contactNumber ?? '',
          role: user.role ?? '',
          specialization: user.specialization ?? '',
          password: '',
          accountStatus: user.accountStatus ?? 'PENDING',
        });
      } catch {
        showToast('Failed to load user data.', 'error');
        setTimeout(() => router.push('/admin/users'), 1500);
      } finally {
        setIsLoadingUser(false);
      }
    };

    fetchUser();
  }, [userId, router]);

  const handleSubmit = async (data: UserFormData) => {
    setIsSubmitting(true);
    try {
      const res = await fetch(`/api/admin/users/${userId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(data),
      });

      if (res.ok) {
        showToast('User updated successfully!', 'success');
        setTimeout(() => router.back(), 800);
      } else {
        const err = await res.json();
        showToast(err.error || 'Failed to update user.', 'error');
        setIsSubmitting(false);
      }
    } catch {
      showToast('An unexpected error occurred.', 'error');
      setIsSubmitting(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#F1F5F9]">
      {/* Focused Top Bar */}
      <header className="bg-white/80 backdrop-blur-md fixed top-0 right-0 w-full z-40 border-b border-slate-200 shadow-sm flex justify-between items-center px-8 h-16">
        <div className="flex items-center gap-4">
          <button
            onClick={() => router.back()}
            className="text-slate-500 hover:text-slate-800 transition-colors p-1 rounded-lg hover:bg-slate-100"
            aria-label="Go back"
          >
            <span className="material-symbols-outlined text-2xl">arrow_back</span>
          </button>
          <h1 className="font-h2 text-h2 text-slate-900 truncate max-w-[500px]">
            {isLoadingUser
              ? 'Edit User'
              : fullName
              ? `Edit User — ${fullName}`
              : 'Edit User'}
          </h1>
        </div>
        <button
          className="text-slate-500 hover:bg-slate-50 rounded-full p-2 transition-colors"
          aria-label="Help"
        >
          <span className="material-symbols-outlined">help_outline</span>
        </button>
      </header>

      {/* Main Content */}
      <main className="w-full pt-[80px] px-4 md:px-8 pb-8 overflow-y-auto">
        <div className="max-w-4xl mx-auto mt-12 bg-white rounded-xl border-b-2 border-primary/10 overflow-hidden shadow-[0_20px_50px_rgba(0,0,0,0.05),0_10px_30px_rgba(0,0,0,0.02)]">
          {isLoadingUser ? (
            <EditUserSkeleton />
          ) : initialData ? (
            <UserForm
              mode="edit"
              initialData={initialData}
              onSubmit={handleSubmit}
              isSubmitting={isSubmitting}
            />
          ) : null}
        </div>
      </main>

      {/* Toast */}
      {toast.show && (
        <Toast
          message={toast.message}
          type={toast.type}
          onDismiss={() => setToast((t) => ({ ...t, show: false }))}
        />
      )}
    </div>
  );
}

/** Loading skeleton while user data is being fetched */
function EditUserSkeleton() {
  const SkeletonBar = ({ w = 'w-full', h = 'h-4' }: { w?: string; h?: string }) => (
    <div className={`${w} ${h} rounded-md bg-slate-200 animate-pulse`} />
  );

  return (
    <div className="px-8 py-6 flex flex-col gap-6">
      {/* Header skeleton */}
      <div className="border-b border-slate-100 pb-6 flex flex-col gap-2">
        <SkeletonBar w="w-48" h="h-6" />
        <SkeletonBar w="w-72" h="h-4" />
      </div>

      {/* Section label */}
      <SkeletonBar w="w-36" h="h-3" />

      {/* Fields grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {Array.from({ length: 6 }).map((_, i) => (
          <div key={i} className="flex flex-col gap-2">
            <SkeletonBar w="w-24" h="h-3" />
            <SkeletonBar h="h-10" />
          </div>
        ))}
      </div>

      {/* Divider */}
      <div className="h-px bg-slate-200 animate-pulse" />

      {/* Security section skeleton */}
      <SkeletonBar w="w-36" h="h-3" />
      <div className="h-16 rounded-lg bg-slate-200 animate-pulse" />

      {/* Button area */}
      <div className="flex justify-end gap-4 pt-6 border-t border-slate-100">
        <SkeletonBar w="w-24" h="h-10" />
        <SkeletonBar w="w-32" h="h-10" />
      </div>
    </div>
  );
}

