export async function PUT(
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) {
  const auth = await verifyAdmin();
  if ('error' in auth) {
    return NextResponse.json({ error: auth.error }, { status: auth.status });
  }

  const { id } = await params;

  let body: any;
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: 'Invalid JSON body' }, { status: 400 });
  }

  const {
    firstName,
    lastName,
    email,
    idNumber,
    department,
    contactNumber,
    specialization,
    accountStatus,
  } = body;

  if (!firstName || !lastName || !email || !idNumber || !department || !specialization) {
    return NextResponse.json({ error: 'Missing required fields' }, { status: 400 });
  }

  try {
    // Check if user is technician
    const existingUser = await prisma.user.findUnique({
      where: { id },
      select: { role: true }
    });

    if (!existingUser || existingUser.role !== 'TECHNICIAN') {
      return NextResponse.json({ error: 'Target user is not a technician' }, { status: 403 });
    }

    // Check email uniqueness excluding self
    const emailConflict = await prisma.user.findFirst({
      where: { email, NOT: { id } },
    });
    if (emailConflict) {
      return NextResponse.json({ error: 'A user with this email already exists.' }, { status: 409 });
    }

    // Check idNumber uniqueness excluding self
    const idConflict = await prisma.user.findFirst({
      where: { idNumber, NOT: { id } },
    });
    if (idConflict) {
      return NextResponse.json({ error: 'A user with this ID number already exists.' }, { status: 409 });
    }

    const updatedUser = await prisma.user.update({
      where: { id },
      data: {
        firstName,
        lastName,
        email,
        idNumber,
        department,
        contactNumber: contactNumber || null,
        specialization,
        accountStatus,
        updatedAt: new Date(),
      },
      select: {
        id: true,
        firstName: true,
        lastName: true,
        email: true,
        idNumber: true,
        department: true,
        contactNumber: true,
        role: true,
        specialization: true,
        accountStatus: true,
        avatarUrl: true,
        createdAt: true,
        updatedAt: true,
      },
    });

    // Audit log
    await prisma.auditLog.create({
      data: {
        userId: auth.userId,
        action: 'USER_UPDATED',
        affectedRecordId: id,
        affectedRecordType: 'User',
        details: `Admin updated technician ${firstName} ${lastName} (${email})`,
      },
    });

    return NextResponse.json(updatedUser);
  } catch (error) {
    console.error(`[PUT /api/admin/technicians/${id}]`, error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

