    lastName,
    email,
    idNumber,
    department,
    contactNumber,
    role,
    specialization,
    accountStatus,
  } = body;

  // Server-side validation
  if (!firstName || !lastName || !email || !idNumber || !department || !role) {
    return NextResponse.json({ error: 'Missing required fields' }, { status: 400 });
  }
  if (role === 'TECHNICIAN' && !specialization) {
    return NextResponse.json({ error: 'Specialization is required for Technicians' }, { status: 400 });
  }

  try {
    // Check email uniqueness excluding self
    const emailConflict = await prisma.user.findFirst({
      where: { email, NOT: { id } },
    });
    if (emailConflict) {
      return NextResponse.json({ error: 'A user with this email already exists.' }, { status: 409 });
    }

    // Check idNumber uniqueness excluding self
    const idConflict = await prisma.user.findFirst({
      where: { idNumber, NOT: { id } },
    });
    if (idConflict) {
      return NextResponse.json({ error: 'A user with this ID number already exists.' }, { status: 409 });
    }

    const updatedUser = await prisma.user.update({
      where: { id },
      data: {
        firstName,
        lastName,
        email,
        idNumber,
        department,
        contactNumber: contactNumber || null,
        role,
        specialization: role === 'TECHNICIAN' ? specialization : null,
        accountStatus,
        updatedAt: new Date(),
      },
      select: {
        id: true,
        firstName: true,
        lastName: true,
        email: true,
        idNumber: true,
        department: true,
        contactNumber: true,
        role: true,
        specialization: true,
        accountStatus: true,
        avatarUrl: true,
        createdAt: true,
        updatedAt: true,
      },
    });

    // Audit log
    await prisma.auditLog.create({
      data: {
        userId: auth.userId,
        action: 'USER_UPDATED',
        affectedRecordId: id,
        affectedRecordType: 'User',
        details: `Admin updated user ${firstName} ${lastName} (${email})`,
      },
    });

    return NextResponse.json(updatedUser);
  } catch (error) {
    console.error(`[PUT /api/admin/users/${id}]`, error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';
import { prisma } from '@/lib/prisma';
import bcrypt from 'bcryptjs';
import type { Prisma } from '@prisma/client';

async function verifyAdmin() {
  const supabase = await createClient();
  const {
    data: { user: authUser },
  } = await supabase.auth.getUser();

  if (!authUser) return { error: 'Unauthorized', status: 401 as const };

  const user = await prisma.user.findUnique({
    where: { id: authUser.id },
    select: { id: true, role: true },
  });

  if (!user) return { error: 'Unauthorized', status: 401 as const };
  if (user.role !== 'ADMIN') return { error: 'Forbidden', status: 403 as const };

  return { userId: user.id };
}

export async function GET(request: NextRequest) {
  const auth = await verifyAdmin();
  if ('error' in auth) {
    return NextResponse.json({ error: auth.error }, { status: auth.status });
  }

  const { searchParams } = request.nextUrl;
  const page = Math.max(1, parseInt(searchParams.get('page') ?? '1', 10));
  const limit = Math.max(1, parseInt(searchParams.get('limit') ?? '10', 10));
  const search = searchParams.get('search')?.trim() ?? '';
  const role = searchParams.get('role')?.trim() ?? '';
  const status = searchParams.get('status')?.trim() ?? '';

  const where: Prisma.UserWhereInput = {
    ...(search && {
      OR: [
        { firstName: { contains: search, mode: 'insensitive' } },
        { lastName: { contains: search, mode: 'insensitive' } },
        { email: { contains: search, mode: 'insensitive' } },
        { idNumber: { contains: search, mode: 'insensitive' } }
      ]
    }),
    ...(role && { role: role as Prisma.EnumUserRoleFilter }),
    ...(status && { accountStatus: status as Prisma.EnumAccountStatusFilter })
  };

  try {
    const [users, total] = await Promise.all([
      prisma.user.findMany({
        where,
        skip: (page - 1) * limit,
        take: limit,
        orderBy: { createdAt: 'desc' },
        select: {
          id: true,
          firstName: true,
          lastName: true,
          email: true,
          idNumber: true,
          department: true,
          role: true,
          specialization: true,
          accountStatus: true,
          avatarUrl: true,
          createdAt: true,
        }
      }),
      prisma.user.count({ where })
    ]);

    return NextResponse.json({
      users,
      pagination: {
        total,
        page,
        limit,
        totalPages: Math.ceil(total / limit)
      }
    });
  } catch (error) {
    console.error('[GET /api/admin/users]', error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

// ── POST /api/admin/users — Create a new user ──────────────────────────────
export async function POST(request: NextRequest) {
  const auth = await verifyAdmin();
  if ('error' in auth) {
    return NextResponse.json({ error: auth.error }, { status: auth.status });
  }

  let body: any;
  try {
    body = await request.json();
  } catch {
    return NextResponse.json({ error: 'Invalid JSON body' }, { status: 400 });
  }

  const {
    firstName,
    lastName,
    email,
    idNumber,
    department,
    contactNumber,
    role,
    specialization,
    password,
    accountStatus,
  } = body;

  // Server-side required field validation
  if (!firstName || !lastName || !email || !idNumber || !department || !role || !password) {
    return NextResponse.json({ error: 'Missing required fields' }, { status: 400 });
  }
  if (role === 'TECHNICIAN' && !specialization) {
    return NextResponse.json({ error: 'Specialization is required for Technicians' }, { status: 400 });
  }
  if (password.length < 8) {
    return NextResponse.json({ error: 'Password must be at least 8 characters' }, { status: 400 });
  }

  try {
    // Check email uniqueness
    const emailExists = await prisma.user.findUnique({ where: { email } });
    if (emailExists) {
      return NextResponse.json({ error: 'A user with this email already exists.' }, { status: 409 });
    }

    // Check idNumber uniqueness
    const idExists = await prisma.user.findUnique({ where: { idNumber } });
    if (idExists) {
      return NextResponse.json({ error: 'A user with this ID number already exists.' }, { status: 409 });
    }

    // Hash password
    const passwordHash = await bcrypt.hash(password, 12);

    // Create user
    const newUser = await prisma.user.create({
      data: {
        firstName,
        lastName,
        email,
        idNumber,
        department,
        contactNumber: contactNumber || null,
        role,
        specialization: role === 'TECHNICIAN' ? specialization : null,
        passwordHash,
        accountStatus: accountStatus || 'PENDING',
      },
      select: {
        id: true,
        firstName: true,
        lastName: true,
        email: true,
        idNumber: true,
        department: true,
        contactNumber: true,
        role: true,
        specialization: true,
        accountStatus: true,
        avatarUrl: true,
        createdAt: true,
        updatedAt: true,
      },
    });

    // Audit log
    await prisma.auditLog.create({
      data: {
        userId: auth.userId,
        action: 'USER_CREATED',
        affectedRecordId: newUser.id,
        affectedRecordType: 'User',
        details: `Admin created user ${firstName} ${lastName} (${email}) with role ${role}`,
      },
    });

    return NextResponse.json(newUser, { status: 201 });
  } catch (error) {
    console.error('[POST /api/admin/users]', error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

import { NextResponse } from 'next/server';
import prisma from '@/lib/prisma';

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { userId } = body;

    if (!userId) {
      return NextResponse.json(
        { message: 'Missing user ID' },
        { status: 400 }
      );
    }

    const user = await prisma.user.findUnique({
      where: { id: userId },
      select: { role: true, accountStatus: true },
    });

    if (!user) {
      return NextResponse.json(
        { message: 'User account not found in the system.' },
        { status: 404 }
      );
    }

    if (user.accountStatus === 'INACTIVE') {
      return NextResponse.json(
        { message: 'Your account has been deactivated. Please contact the administrator.' },
        { status: 403 }
      );
    }

    return NextResponse.json({ role: user.role }, { status: 200 });
  } catch (error: any) {
    console.error('Error in /api/auth/login:', error);
    return NextResponse.json(
      { 
        message: 'Internal server error',
        debug: error.message,
        stack: error.stack 
      },
      { status: 500 }
    );
  }
}

import { NextResponse } from 'next/server';
import prisma from '@/lib/prisma';
import { createClient } from '@supabase/supabase-js';
import bcrypt from 'bcryptjs';

export async function POST(request: Request) {
  try {
    const body = await request.json();
    const { firstName, lastName, email, idNumber, department, password } = body;

    // Validate required fields
    if (!firstName || !lastName || !email || !idNumber || !department || !password) {
      return NextResponse.json({ message: 'All fields are required.' }, { status: 400 });
    }

    // Step 1: Check for duplicate email
    const existingUserEmail = await prisma.user.findUnique({
      where: { email },
    });

    if (existingUserEmail) {
      return NextResponse.json({ message: 'An account with this email already exists.' }, { status: 409 });
    }

    // Step 2: Check for duplicate ID number
    const existingUserIdNumber = await prisma.user.findUnique({
      where: { idNumber },
    });

    if (existingUserIdNumber) {
      return NextResponse.json({ message: 'An account with this ID number already exists.' }, { status: 409 });
    }

    // Create supabase admin client
    const supabaseAdmin = createClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY! // fallback if service_role is not provided locally
    );

    // Step 3: Create Supabase Auth user
    const { data: supabaseUser, error: supabaseError } = await supabaseAdmin.auth.admin.createUser({
      email,
      password,
      email_confirm: true,
    });

    if (supabaseError || !supabaseUser.user) {
      return NextResponse.json(
        { message: supabaseError?.message || 'Error creating user in Supabase.' },
        { status: 500 }
      );
    }

    // Hash password for Prisma
    const hashedPassword = await bcrypt.hash(password, 12);

    // Step 4: Create Prisma User record — role is always USER for public registration
    await prisma.user.create({
      data: {
        id: supabaseUser.user.id,
        email,
        passwordHash: hashedPassword,
        firstName,
        lastName,
        idNumber,
        department,
        role: 'USER',
        accountStatus: 'ACTIVE',
      },
    });

    // Step 5: Return success
    return NextResponse.json(
      { message: 'Registration successful. Your account is now active — you can log in immediately.' },
      { status: 201 }
    );
  } catch (error: any) {
    console.error('Registration error:', error);
    return NextResponse.json(
      { message: 'An unexpected error occurred. Please try again.' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';
import { prisma } from '@/lib/prisma';

export async function GET(request: NextRequest) {
  try {
    const supabase = await createClient();
    const { data: { user: authUser } } = await supabase.auth.getUser();

    if (!authUser) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    const { searchParams } = new URL(request.url);
    const role = searchParams.get('role');
    const status = searchParams.get('status');
    const limit = parseInt(searchParams.get('limit') || '50', 10);

    const where: any = {};
    if (role) where.role = role;
    if (status) where.accountStatus = status;

    const users = await prisma.user.findMany({
      where,
      take: limit,
      select: {
        id: true,
        firstName: true,
        lastName: true,
        email: true,
        role: true,
        department: true,
        specialization: true,
        avatarUrl: true,
        accountStatus: true,
        _count: {
          select: {
            assignedRequests: {
              where: { status: 'ONGOING' }
            }
          }
        }
      },
      orderBy: { firstName: 'asc' }
    });

    // Format the count for the frontend which might expect tech.activeTaskCount or tech._count.assignedRequests
    const formattedUsers = users.map(user => ({
      ...user,
      activeTaskCount: user._count.assignedRequests
    }));

    return NextResponse.json({ users: formattedUsers });
  } catch (error) {
    console.error('[GET /api/users]', error);
    return NextResponse.json({ error: 'Internal Server Error' }, { status: 500 });
  }
}

