import React from 'react';

interface ActivityLogProps {
  statusHistory: any[];
}

export default function ActivityLog({ statusHistory }: ActivityLogProps) {
  const formatTimestamp = (dateString: string) => {
    const date = new Date(dateString);
    const now = new Date();
    const isToday = date.getDate() === now.getDate() && date.getMonth() === now.getMonth() && date.getFullYear() === now.getFullYear();
    const timeFormat = date.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    if (isToday) {
      return `Today, ${timeFormat}`;
    }
    return `${date.toLocaleDateString('en-US', { month: 'short', day: '2-digit' })}, ${timeFormat}`;
  };

  const getActionDescription = (item: any) => {
    if (item.remarks) return item.remarks;
    if (item.previousStatus && item.newStatus) {
      return `Status changed from ${item.previousStatus} to ${item.newStatus}`;
    }
    if (!item.previousStatus && item.newStatus === 'PENDING') {
      return 'Request Submitted';
    }
    return `Status updated to ${item.newStatus}`;
  };

  return (
    <div className="bg-surface rounded-xl overflow-hidden border border-outline-variant shadow-sm p-6 mb-6">
      <h3 className="text-lg font-bold text-on-surface mb-6">Activity Log</h3>

      {statusHistory.length === 0 ? (
        <p className="text-on-surface-variant text-sm">No activity recorded yet.</p>
      ) : (
        <div className="relative pl-4 border-l-2 border-surface-container space-y-8">
          {statusHistory.map((item, index) => {
            const isMostRecent = index === 0;
            return (
              <div key={item.id} className="relative">
                {/* Timeline Dot */}
                <div
                  className={`absolute -left-[21px] top-1 w-3 h-3 rounded-full border-2 border-surface ${
                    isMostRecent ? 'bg-secondary-container' : 'bg-surface-container-highest'
                  }`}
                />

                {/* Log Content */}
                <div>
                  <p className="text-on-surface font-medium">{getActionDescription(item)}</p>
                  <p className="text-xs text-on-surface-variant mt-1">
                    {formatTimestamp(item.changedAt)}
                  </p>
                  <p className="text-xs text-on-surface-variant mt-1">
                    by {item.actor?.firstName} {item.actor?.lastName} {item.actor?.role ? `(${item.actor.role})` : ''}
                  </p>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

'use client';

import React, { useState, useEffect } from 'react';
import Image from 'next/image';

interface AdminActionCardProps {
  request: any;
  onRefresh: () => void;
}

export default function AdminActionCard({ request, onRefresh }: AdminActionCardProps) {
  const [priority, setPriority] = useState(request.priorityLevel || 'NORMAL');
  const [adminNotes, setAdminNotes] = useState(request.adminNotes || '');
  const [isUpdating, setIsUpdating] = useState(false);

  // Technician assignment state
  const [showTechSelector, setShowTechSelector] = useState(false);
  const [technicians, setTechnicians] = useState<any[]>([]);
  const [selectedTechId, setSelectedTechId] = useState<string | null>(null);

  // Modal state
  const [modalOpen, setModalOpen] = useState(false);
  const [modalType, setModalType] = useState<'reject' | 'cancel' | null>(null);
  const [modalReason, setModalReason] = useState('');

  const priorities = ['LOW', 'NORMAL', 'HIGH', 'URGENT'];

  const getPriorityColor = (p: string) => {
    switch (p) {
      case 'URGENT': return 'text-error';
      case 'HIGH': return 'text-orange-500';
      case 'NORMAL': return 'text-secondary';
      case 'LOW': return 'text-outline';
      default: return 'text-outline';
    }
  };

  const handlePriorityChange = async (newPriority: string) => {
    setPriority(newPriority);
    setIsUpdating(true);
    try {
      await fetch(`/api/admin/requests/${request.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'updatePriority', priorityLevel: newPriority }),
      });
      onRefresh();
    } catch (error) {
      console.error('Failed to update priority', error);
    } finally {
      setIsUpdating(false);
    }
  };

  const fetchTechnicians = async () => {
    try {
      const res = await fetch('/api/users?role=TECHNICIAN&status=ACTIVE');
      if (res.ok) {
        const data = await res.json();
        setTechnicians(data.users || data);
      }
    } catch (error) {
      console.error('Failed to fetch technicians', error);
    }
  };

  const handleTechChangeClick = () => {
    setShowTechSelector(!showTechSelector);
    if (!showTechSelector && technicians.length === 0) {
      fetchTechnicians();
    }
  };

  const confirmAssignment = async () => {
    if (!selectedTechId) return;
    setIsUpdating(true);
    try {
      await fetch(`/api/admin/requests/${request.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'assign', technicianId: selectedTechId }),
      });
      setShowTechSelector(false);
      onRefresh();
    } catch (error) {
      console.error('Failed to assign technician', error);
    } finally {
      setIsUpdating(false);
    }
  };

  const handleApprove = async () => {
    setIsUpdating(true);
    try {
      await fetch(`/api/admin/requests/${request.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          action: 'approve', 
          priorityLevel: priority, 
          adminNotes,
          assignedToId: selectedTechId || request.assignedToId
        }),
      });
      onRefresh();
    } catch (error) {
      console.error('Failed to approve request', error);
    } finally {
      setIsUpdating(false);
    }
  };

  const openModal = (type: 'reject' | 'cancel') => {
    setModalType(type);
    setModalReason('');
    setModalOpen(true);
  };

  const confirmModalAction = async () => {
    if (modalReason.length < 20 || !modalType) return;
    setIsUpdating(true);
    try {
      await fetch(`/api/admin/requests/${request.id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ 
          action: modalType, 
          [`${modalType}Reason`]: modalReason 
        }),
      });
      setModalOpen(false);
      onRefresh();
    } catch (error) {
      console.error(`Failed to ${modalType} request`, error);
    } finally {
      setIsUpdating(false);
    }
  };

  const getInitials = (firstName: string, lastName: string) => {
    return `${firstName?.[0] || ''}${lastName?.[0] || ''}`.toUpperCase();
