                className={`flex-1 text-xs font-bold py-2 rounded-md transition-all ${
                  priority === p 
                    ? `bg-white shadow-sm ${getPriorityColor(p)}` 
                    : 'text-on-surface-variant hover:bg-surface-container hover:text-on-surface'
                }`}
              >
